import org.junit.jupiter.api.Test

class SpacingAroundColonRuleAnnotationTest {
    private val spacingAroundColonRuleAssertThat = assertThatRule { SpacingAroundColonRule() }

    @Test
    fun `Given valid annotation use-site targets without spacing`() {
        // https://kotlinlang.org/docs/annotations.html#annotation-use-site-targets
        val code =
            """
            @file:JvmName("Foo")
            class Example(@field:Ann val foo: String, @get:Ann val bar: String)
            class Example {
                @set:[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            fun @receiver:Fancy String.myExtension() { }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given annotation with spacing before colon`() {
        val code =
            """
            @file :JvmName("Foo")
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(1, 6, "Unexpected spacing before \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given annotation with spacing after colon`() {
        val code =
            """
            @file: JvmName("Foo")
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(1, 6, "Unexpected spacing after \":\"")
            .isFormattedAs(formattedCode)
    }

