            class Example(@field : Ann val foo: String)
            """.trimIndent()
        val formattedCode =
            """
            class Example(@field:Ann val foo: String)
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(1, 21, "Unexpected spacing around \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given set annotation use-site target with spacing before colon`() {
        val code =
            """
            class Example {
                @set :[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        val formattedCode =
            """
            class Example {
                @set:[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(2, 9, "Unexpected spacing before \":\"")
            .isFormattedAs(formattedCode)
    }

