            }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(2, 9, "Unexpected spacing after \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given set annotation use-site target with spacing around colon`() {
        val code =
            """
            class Example {
                @set : [Inject VisibleForTesting]
